#include <stdio.h>
#include <stdlib.h>

#include "rango.h"

void eliminarRango(Nodo **phead, double y, double z) {
    Nodo *prev = NULL;
    Nodo *curr = *phead;

    // Recorrer la lista hasta encontrar el primer nodo con x >= y.
    // Esos son los candidatos a borrar (la lista esta ordenada
    // ascendentemente).
    while (curr != NULL && curr->x < y) {
        prev = curr;
        curr = curr->prox;
    }

    // curr es el primer nodo a eliminar (puede ser NULL).
    // Eliminar todos los nodos con x <= z, avanzando curr.
    while (curr != NULL && curr->x <= z) {
        Nodo *next = curr->prox;
        free(curr);
        curr = next;
    }

    // Reconectar la lista saltando los nodos eliminados.
    if (prev != NULL) {
        prev->prox = curr;
    } else {
        // El primer nodo (o mas) fue eliminado.
        *phead = curr;
    }
}

