// Minimal ZIP writer (STORE method, no compression)
// Produces a valid zip file compatible with unzip, 7z, etc.
// Source: https://en.wikipedia.org/wiki/ZIP_(file_format)
const fs = require('fs');
const path = require('path');

function u32(n) {
  const b = Buffer.alloc(4);
  b.writeUInt32LE(n >>> 0, 0);
  return b;
}
function u16(n) {
  const b = Buffer.alloc(2);
  b.writeUInt16LE(n & 0xffff, 0);
  return b;
}

function dosTime(d = new Date()) {
  const t =
    ((d.getHours() & 0x1f) << 11) |
    ((d.getMinutes() & 0x3f) << 5) |
    ((d.getSeconds() >> 1) & 0x1f);
  const dd =
    (((d.getFullYear() - 1980) & 0x7f) << 9) |
    (((d.getMonth() + 1) & 0x0f) << 5) |
    (d.getDate() & 0x1f);
  return { time: t, date: dd };
}

function addFile(name, data, now) {
  const nameBuf = Buffer.from(name);
  const crc = require('zlib').crc32 ? require('zlib').crc32(data) : crc32(data);
  const size = data.length;
  const { time, date } = dosTime(now);
  const local = Buffer.concat([
    u32(0x04034b50),          // local file header signature
    u16(20),                  // version needed (2.0)
    u16(0x0800),              // flags: utf-8
    u16(0),                   // compression: store
    u16(time),                // mod time
    u16(date),                // mod date
    u32(crc),                 // crc-32
    u32(size),                // compressed size
    u32(size),                // uncompressed size
    u16(nameBuf.length),      // file name length
    u16(0),                   // extra field length
    nameBuf,
  ]);
  return { local, data, nameBuf, crc, size, time, date };
}

// Pure-JS CRC32 (table-based)
let crcTable = null;
function crc32(buf) {
  if (!crcTable) {
    crcTable = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let k = 0; k < 8; k++) {
        c = (c & 1) ? (0xedb88320 ^ (c >>> 1)) : (c >>> 1);
      }
      crcTable[i] = c >>> 0;
    }
  }
  let c = 0xffffffff;
  for (let i = 0; i < buf.length; i++) {
    c = crcTable[(c ^ buf[i]) & 0xff] ^ (c >>> 8);
  }
  return (c ^ 0xffffffff) >>> 0;
}

function addFileJS(name, data) {
  const nameBuf = Buffer.from(name);
  const crc = crc32(data);
  const size = data.length;
  const { time, date } = dosTime();
  const local = Buffer.concat([
    u32(0x04034b50),
    u16(20),
    u16(0x0800),
    u16(0),
    u16(time),
    u16(date),
    u32(crc),
    u32(size),
    u32(size),
    u16(nameBuf.length),
    u16(0),
    nameBuf,
  ]);
  return { local, data, nameBuf, crc, size, time, date };
}

const files = ['rango.c', 'resultados.txt'];
const entries = [];
let offset = 0;
const now = new Date();

for (const f of files) {
  const data = fs.readFileSync(f);
  const e = addFileJS(f, data);
  e.offset = offset;
  entries.push(e);
  offset += e.local.length + e.data.length;
}

// Central directory entries
let cd = Buffer.alloc(0);
for (const e of entries) {
  const ent = Buffer.concat([
    u32(0x02014b50),          // central dir header signature
    u16(20),                  // version made by
    u16(20),                  // version needed
    u16(0x0800),              // flags
    u16(0),                   // compression
    u16(e.time),
    u16(e.date),
    u32(e.crc),
    u32(e.size),              // compressed
    u32(e.size),              // uncompressed
    u16(e.nameBuf.length),
    u16(0),                   // extra length
    u16(0),                   // comment length
    u16(0),                   // disk number
    u16(0),                   // internal attrs
    u32(0),                   // external attrs
    u32(e.offset),            // local header offset
    e.nameBuf,
  ]);
  cd = Buffer.concat([cd, ent]);
}

const cdOffset = offset;
const cdSize = cd.length;

// End of central dir record
const eocd = Buffer.concat([
  u32(0x06054b50),
  u16(0), u16(0),                       // disk
  u16(entries.length), u16(entries.length),
  u32(cdSize), u32(cdOffset),
  u16(0),                                // comment length
]);

const out = Buffer.concat([
  ...entries.flatMap(e => [e.local, e.data]),
  cd,
  eocd,
]);

fs.writeFileSync('rango.zip', out);
console.log('Wrote rango.zip (' + out.length + ' bytes) with entries:', entries.map(e => e.nameBuf.toString()).join(', '));

